import{_ as s,H as n,f as t,i as e}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"容灾与备份","description":"","frontmatter":{},"headers":[],"relativePath":"../systemDesign/26-容灾与备份.md","filePath":"../systemDesign/26-容灾与备份.md","lastUpdated":1778496697000}'),l={name:"../systemDesign/26-容灾与备份.md"};function i(o,a,p,r,d,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="容灾与备份" tabindex="-1">容灾与备份 <a class="header-anchor" href="#容灾与备份" aria-label="Permalink to &quot;容灾与备份&quot;">​</a></h1><p>容灾和备份是<strong>所有架构里最容易被低估的部分</strong>——平时没人在乎,出事时它是公司命脉。&quot;我们有备份&quot;是真的最便宜的安慰剂——<strong>备份没演练过 = 没有备份</strong>。GitLab 2017 年那次事故就是教训:有 5 套备份,真出事时<strong>5 套全失效或不完整</strong>,丢了 6 小时数据,公司差点死掉。这一篇讲清楚:<strong>RTO / RPO 怎么定义</strong>,备份的几种形式,<strong>两地三中心</strong> 的工程含义,和<strong>故障演练(Game Day)</strong> 这个被严重低估的实践。</p><blockquote><p>一句话先记住:<strong>容灾的两个核心指标是 RTO(多久能恢复)和 RPO(能丢多少数据)</strong>——它们决定备份策略。<strong>备份分热 / 温 / 冷三层</strong>,各对应不同 RPO。<strong>两地三中心</strong>不是地理概念,是架构能力——同城两份保 RTO,异地一份保灾难。<strong>最关键的纪律:每季度做一次&quot;假装机房挂了&quot;的真实演练</strong>——平时不练,真出事时所有备份都没用。</p></blockquote><hr><h2 id="一、容灾的两个核心指标-rto-rpo" tabindex="-1">一、容灾的两个核心指标:RTO / RPO <a class="header-anchor" href="#一、容灾的两个核心指标-rto-rpo" aria-label="Permalink to &quot;一、容灾的两个核心指标:RTO / RPO&quot;">​</a></h2><h3 id="_1-1-rto-recovery-time-objective-多久能恢复" tabindex="-1">1.1 RTO(Recovery Time Objective):多久能恢复 <a class="header-anchor" href="#_1-1-rto-recovery-time-objective-多久能恢复" aria-label="Permalink to &quot;1.1 RTO(Recovery Time Objective):多久能恢复&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>故障发生 → 业务恢复</span></span>
<span class="line"><span>        ↑ 这段时间就是 RTO</span></span></code></pre></div><p><strong>典型 RTO 等级</strong>:</p><table tabindex="0"><thead><tr><th>业务类型</th><th>RTO 要求</th></tr></thead><tbody><tr><td>内部工具</td><td>几小时-几天</td></tr><tr><td>中等业务</td><td>30 分钟-2 小时</td></tr><tr><td>核心业务</td><td>5-30 分钟</td></tr><tr><td>金融核心 / 支付</td><td>&lt; 5 分钟</td></tr><tr><td>极致(银行 / 电信)</td><td>&lt; 1 分钟</td></tr></tbody></table><h3 id="_1-2-rpo-recovery-point-objective-能丢多少数据" tabindex="-1">1.2 RPO(Recovery Point Objective):能丢多少数据 <a class="header-anchor" href="#_1-2-rpo-recovery-point-objective-能丢多少数据" aria-label="Permalink to &quot;1.2 RPO(Recovery Point Objective):能丢多少数据&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最近一次有效备份 → 故障发生</span></span>
<span class="line"><span>                  ↑ 这段未备份的数据可能丢失,就是 RPO</span></span></code></pre></div><p><strong>典型 RPO 等级</strong>:</p><table tabindex="0"><thead><tr><th>业务类型</th><th>RPO 要求</th></tr></thead><tbody><tr><td>普通业务</td><td>1 天(每天一次全量备份)</td></tr><tr><td>重要业务</td><td>1 小时</td></tr><tr><td>核心业务</td><td>几分钟</td></tr><tr><td>金融</td><td>0(强同步,不能丢)</td></tr></tbody></table><h3 id="_1-3-rto-和-rpo-的成本曲线" tabindex="-1">1.3 RTO 和 RPO 的成本曲线 <a class="header-anchor" href="#_1-3-rto-和-rpo-的成本曲线" aria-label="Permalink to &quot;1.3 RTO 和 RPO 的成本曲线&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RTO / RPO     成本</span></span>
<span class="line"><span>1 天          $</span></span>
<span class="line"><span>1 小时        $$</span></span>
<span class="line"><span>30 分钟       $$$</span></span>
<span class="line"><span>5 分钟        $$$$</span></span>
<span class="line"><span>1 分钟        $$$$$</span></span>
<span class="line"><span>0 (永不丢)   $$$$$$ (天文数字)</span></span></code></pre></div><p><strong>关键决策</strong>:<strong>业务方决定 RTO/RPO,技术方实现</strong>。不要技术拍脑袋&quot;我觉得 RPO 1 小时差不多&quot;——业务说不行就是不行。</p><hr><h2 id="二、备份的三层" tabindex="-1">二、备份的三层 <a class="header-anchor" href="#二、备份的三层" aria-label="Permalink to &quot;二、备份的三层&quot;">​</a></h2><p>按&quot;恢复速度 vs 成本&quot;分:</p><h3 id="_2-1-热备份-hot-backup" tabindex="-1">2.1 热备份(Hot Backup) <a class="header-anchor" href="#_2-1-热备份-hot-backup" aria-label="Permalink to &quot;2.1 热备份(Hot Backup)&quot;">​</a></h3><p><strong>实时同步,RPO 几乎 0,RTO 几秒</strong>:</p><ul><li>MySQL 主从半同步</li><li>Redis 主从复制</li><li>Cell 间双活同步</li></ul><p><strong>成本</strong>:<strong>双倍硬件</strong>(永远有一份在跑),贵。 <strong>适合</strong>:核心业务的灾备。</p><h3 id="_2-2-温备份-warm-backup" tabindex="-1">2.2 温备份(Warm Backup) <a class="header-anchor" href="#_2-2-温备份-warm-backup" aria-label="Permalink to &quot;2.2 温备份(Warm Backup)&quot;">​</a></h3><p><strong>定期同步,RPO 几分钟到 1 小时,RTO 几十分钟</strong>:</p><ul><li>每小时增量备份</li><li>每天全量备份</li><li>备份机定期演练启动</li></ul><p><strong>成本</strong>:<strong>0.5-1 倍硬件</strong>(备份系统较小)。 <strong>适合</strong>:中等业务。</p><h3 id="_2-3-冷备份-cold-backup" tabindex="-1">2.3 冷备份(Cold Backup) <a class="header-anchor" href="#_2-3-冷备份-cold-backup" aria-label="Permalink to &quot;2.3 冷备份(Cold Backup)&quot;">​</a></h3><p><strong>离线归档,RPO 1 天,RTO 几小时</strong>:</p><ul><li>每天 / 每周备份到对象存储 / 磁带</li><li>出事时下载备份 → 部署 → 启动</li><li>数据可能丢 1 天</li></ul><p><strong>成本</strong>:<strong>极低</strong>(对象存储 / 磁带便宜)。 <strong>适合</strong>:合规归档、历史数据。</p><hr><h2 id="三、数据备份的具体方案" tabindex="-1">三、数据备份的具体方案 <a class="header-anchor" href="#三、数据备份的具体方案" aria-label="Permalink to &quot;三、数据备份的具体方案&quot;">​</a></h2><h3 id="_3-1-mysql-备份" tabindex="-1">3.1 MySQL 备份 <a class="header-anchor" href="#_3-1-mysql-备份" aria-label="Permalink to &quot;3.1 MySQL 备份&quot;">​</a></h3><p><strong>全量</strong>:</p><ul><li><code>mysqldump</code>(逻辑备份,慢但跨版本)</li><li><code>xtrabackup</code>(物理备份,快但要相同版本)</li></ul><p><strong>增量</strong>:</p><ul><li>基于 binlog 的增量</li><li>每小时 / 每天合并到全量</li></ul><p><strong>云上</strong>:</p><ul><li>AWS RDS / 阿里云 RDS 自带&quot;自动备份&quot;</li><li>开启 PITR(Point-in-Time Recovery)→ 可恢复到任意秒</li></ul><h3 id="_3-2-redis-备份" tabindex="-1">3.2 Redis 备份 <a class="header-anchor" href="#_3-2-redis-备份" aria-label="Permalink to &quot;3.2 Redis 备份&quot;">​</a></h3><ul><li><strong>RDB</strong>:定时快照</li><li><strong>AOF</strong>:每条写命令追加(更细粒度)</li><li><strong>AOF + RDB</strong>:两者结合(主流)</li></ul><h3 id="_3-3-对象存储" tabindex="-1">3.3 对象存储 <a class="header-anchor" href="#_3-3-对象存储" aria-label="Permalink to &quot;3.3 对象存储&quot;">​</a></h3><p>S3 / OSS 自带:</p><ul><li><strong>跨区域复制</strong>:自动同步到其他 region</li><li><strong>版本管理</strong>:文件覆盖了能恢复</li><li><strong>生命周期</strong>:N 天后自动归档(降成本)</li></ul><h3 id="_3-4-应用配置" tabindex="-1">3.4 应用配置 <a class="header-anchor" href="#_3-4-应用配置" aria-label="Permalink to &quot;3.4 应用配置&quot;">​</a></h3><p>代码、配置、密钥<strong>也要备份</strong>——常被忽略:</p><ul><li><strong>代码</strong>:git 远程仓库 + 本地多人同步(等于多备份)</li><li><strong>配置</strong>:Nacos / Apollo 自动持久化 + 备份</li><li><strong>密钥</strong>:Vault + 离线纸质副本(银行级)</li></ul><hr><h2 id="四、两地三中心" tabindex="-1">四、两地三中心 <a class="header-anchor" href="#四、两地三中心" aria-label="Permalink to &quot;四、两地三中心&quot;">​</a></h2><p>中国监管对金融行业的硬要求,实际上是<strong>所有重要业务的最佳实践</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 城市:</span></span>
<span class="line"><span>  ┌──────────┐    ┌──────────┐</span></span>
<span class="line"><span>  │ 主数据中心 │ ←→ │ 同城灾备  │</span></span>
<span class="line"><span>  └──────────┘    └──────────┘</span></span>
<span class="line"><span>      ↕  同城同步 (强一致)</span></span>
<span class="line"><span>      ↕</span></span>
<span class="line"><span>B 城市(几百-几千 km 外):</span></span>
<span class="line"><span>  ┌──────────┐</span></span>
<span class="line"><span>  │ 异地灾备  │</span></span>
<span class="line"><span>  └──────────┘</span></span>
<span class="line"><span>      ↑  异地异步同步 (最终一致)</span></span></code></pre></div><h3 id="_4-1-角色" tabindex="-1">4.1 角色 <a class="header-anchor" href="#_4-1-角色" aria-label="Permalink to &quot;4.1 角色&quot;">​</a></h3><ul><li><strong>同城两中心</strong>:<strong>双活</strong>,实时同步,RTO 几分钟</li><li><strong>异地一中心</strong>:<strong>冷备 / 温备</strong>,异步同步,RPO 几小时</li></ul><h3 id="_4-2-灾难场景" tabindex="-1">4.2 灾难场景 <a class="header-anchor" href="#_4-2-灾难场景" aria-label="Permalink to &quot;4.2 灾难场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>切换</th><th>影响</th></tr></thead><tbody><tr><td>单机房硬件挂</td><td>同城自动切换</td><td>RTO 1-5 分钟</td></tr><tr><td>A 城市光纤被挖</td><td>切到 B 城市</td><td>RTO 30 分钟,RPO 几分钟</td></tr><tr><td>A 城市地震</td><td>切到 B 城市</td><td>RTO 几小时(数据可能不全)</td></tr></tbody></table><h3 id="_4-3-三地五中心-顶级" tabindex="-1">4.3 三地五中心(顶级) <a class="header-anchor" href="#_4-3-三地五中心-顶级" aria-label="Permalink to &quot;4.3 三地五中心(顶级)&quot;">​</a></h3><p>阿里、腾讯顶级架构:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 城: 主中心 + 同城灾备</span></span>
<span class="line"><span>B 城: 双活中心 + 同城灾备</span></span>
<span class="line"><span>C 城: 异地容灾(只读)</span></span></code></pre></div><p><strong>任何单地区故障都不影响业务</strong> —— 但成本是 5 倍硬件。</p><hr><h2 id="五、为什么-演练-是关键" tabindex="-1">五、为什么&quot;演练&quot;是关键 <a class="header-anchor" href="#五、为什么-演练-是关键" aria-label="Permalink to &quot;五、为什么&quot;演练&quot;是关键&quot;">​</a></h2><p><strong>没演练过的备份 = 没有备份</strong>——这是行业血泪教训。</p><h3 id="_5-1-真实事故案例" tabindex="-1">5.1 真实事故案例 <a class="header-anchor" href="#_5-1-真实事故案例" aria-label="Permalink to &quot;5.1 真实事故案例&quot;">​</a></h3><ul><li><strong>GitLab 2017</strong>:误删数据库,5 套备份<strong>全失效</strong>(磁盘满了 / 路径错了 / 版本不兼容 / 权限错了 / 备份是空的),最终丢 6 小时数据</li><li><strong>Code Spaces 2014</strong>:被攻击者拿到 AWS 密钥,<strong>删了所有数据 + 备份</strong>,公司直接关门</li><li><strong>某国内电商 2020</strong>:容灾系统部署 2 年没演练过,真灾难来时<strong>切换流程不通</strong>,全平台瘫 4 小时</li></ul><h3 id="_5-2-不演练为什么必出事" tabindex="-1">5.2 不演练为什么必出事 <a class="header-anchor" href="#_5-2-不演练为什么必出事" aria-label="Permalink to &quot;5.2 不演练为什么必出事&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>配置漂移:    主系统升级了,备份系统配置过期</span></span>
<span class="line"><span>权限丢失:    人员变动,备份相关账号被注销</span></span>
<span class="line"><span>路径变更:    数据迁移后备份脚本指向旧路径</span></span>
<span class="line"><span>依赖变化:    依赖的库 / 工具版本不兼容</span></span>
<span class="line"><span>数据格式:    备份格式变了,恢复脚本读不出</span></span></code></pre></div><p><strong>这些问题平时根本看不到——只有演练才能暴露</strong>。</p><hr><h2 id="六、game-day-混沌演练" tabindex="-1">六、Game Day(混沌演练) <a class="header-anchor" href="#六、game-day-混沌演练" aria-label="Permalink to &quot;六、Game Day(混沌演练)&quot;">​</a></h2><p>Netflix 发明的实践——<strong>主动制造故障,验证系统弹性</strong>:</p><h3 id="_6-1-演练等级" tabindex="-1">6.1 演练等级 <a class="header-anchor" href="#_6-1-演练等级" aria-label="Permalink to &quot;6.1 演练等级&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Level 1:  在测试环境随机杀实例</span></span>
<span class="line"><span>Level 2:  在生产环境随机杀实例(Chaos Monkey)</span></span>
<span class="line"><span>Level 3:  生产环境随机断 AZ 的网(Chaos Kong)</span></span>
<span class="line"><span>Level 4:  生产环境模拟整个机房挂(Game Day)</span></span></code></pre></div><h3 id="_6-2-game-day-流程" tabindex="-1">6.2 Game Day 流程 <a class="header-anchor" href="#_6-2-game-day-流程" aria-label="Permalink to &quot;6.2 Game Day 流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 提前公告(团队都在线)</span></span>
<span class="line"><span>2. 模拟故障(切流 / 断网 / 杀实例)</span></span>
<span class="line"><span>3. 观察系统自动恢复 / 切换</span></span>
<span class="line"><span>4. 没自动恢复的部分 → 人工处理</span></span>
<span class="line"><span>5. 复盘:哪些地方做的好 / 哪些有问题</span></span>
<span class="line"><span>6. 修复问题 → 下次演练验证</span></span></code></pre></div><h3 id="_6-3-演练频率" tabindex="-1">6.3 演练频率 <a class="header-anchor" href="#_6-3-演练频率" aria-label="Permalink to &quot;6.3 演练频率&quot;">​</a></h3><ul><li><strong>每月</strong>:小范围演练(单服务 / 单实例)</li><li><strong>每季度</strong>:中等规模(单 AZ 切换)</li><li><strong>每半年</strong>:大规模(机房级)</li><li><strong>每年</strong>:整体灾备演练(异地切换)</li></ul><blockquote><p>没演练过的容灾<strong>99% 失败</strong>;演练过的容灾<strong>99% 成功</strong>。</p></blockquote><hr><h2 id="七、备份的常见错误" tabindex="-1">七、备份的常见错误 <a class="header-anchor" href="#七、备份的常见错误" aria-label="Permalink to &quot;七、备份的常见错误&quot;">​</a></h2><h3 id="_7-1-备份和源数据放在同一磁盘-机房" tabindex="-1">7.1 备份和源数据放在同一磁盘 / 机房 <a class="header-anchor" href="#_7-1-备份和源数据放在同一磁盘-机房" aria-label="Permalink to &quot;7.1 备份和源数据放在同一磁盘 / 机房&quot;">​</a></h3><p>磁盘坏 → 备份也坏。机房挂 → 备份也挂。<strong>备份必须物理隔离</strong>。</p><h3 id="_7-2-不验证备份完整性" tabindex="-1">7.2 不验证备份完整性 <a class="header-anchor" href="#_7-2-不验证备份完整性" aria-label="Permalink to &quot;7.2 不验证备份完整性&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每次备份后:</span></span>
<span class="line"><span>  自动跑一次&quot;取一小段数据校验&quot;,确认能读</span></span>
<span class="line"><span>  每月做一次&quot;完整恢复演练&quot;</span></span></code></pre></div><p>不校验 → 备份是空的也不知道,直到真出事。</p><h3 id="_7-3-备份没加密" tabindex="-1">7.3 备份没加密 <a class="header-anchor" href="#_7-3-备份没加密" aria-label="Permalink to &quot;7.3 备份没加密&quot;">​</a></h3><p>存到 S3 的备份<strong>默认要加密</strong>。备份被偷 = 数据被偷。</p><h3 id="_7-4-备份的备份" tabindex="-1">7.4 备份的备份 <a class="header-anchor" href="#_7-4-备份的备份" aria-label="Permalink to &quot;7.4 备份的备份&quot;">​</a></h3><p><strong>重要数据要&quot;3-2-1&quot;原则</strong>:</p><ul><li><strong>3</strong> 份副本</li><li><strong>2</strong> 种不同介质(SSD + 对象存储)</li><li><strong>1</strong> 份异地</li></ul><h3 id="_7-5-不测试恢复时间" tabindex="-1">7.5 不测试恢复时间 <a class="header-anchor" href="#_7-5-不测试恢复时间" aria-label="Permalink to &quot;7.5 不测试恢复时间&quot;">​</a></h3><p><strong>RTO 是要测的</strong>——别拍脑袋。真测一遍,从备份到业务恢复要多久?可能比你想的久 10 倍。</p><hr><h2 id="八、版本回滚-被忽视的-软件容灾" tabindex="-1">八、版本回滚:被忽视的&quot;软件容灾&quot; <a class="header-anchor" href="#八、版本回滚-被忽视的-软件容灾" aria-label="Permalink to &quot;八、版本回滚:被忽视的&quot;软件容灾&quot;&quot;">​</a></h2><p><strong>故障 80% 来自发版</strong>——回滚是最高频的&quot;容灾&quot;动作。</p><h3 id="_8-1-应用回滚" tabindex="-1">8.1 应用回滚 <a class="header-anchor" href="#_8-1-应用回滚" aria-label="Permalink to &quot;8.1 应用回滚&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新版本部署 → 监控异常 → 立即回滚到旧版本</span></span></code></pre></div><p><strong>前提</strong>:</p><ul><li>镜像 / 包要保留(N 个版本,可回退)</li><li>DB schema 改动<strong>向后兼容</strong>(旧代码也能跑)</li><li>配置回滚跟代码同步</li></ul><h3 id="_8-2-配置回滚" tabindex="-1">8.2 配置回滚 <a class="header-anchor" href="#_8-2-配置回滚" aria-label="Permalink to &quot;8.2 配置回滚&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>配置中心(Nacos / Apollo)→ 推送了错配置 → 一键回滚到上一版本</span></span></code></pre></div><h3 id="_8-3-db-schema-回滚" tabindex="-1">8.3 DB schema 回滚 <a class="header-anchor" href="#_8-3-db-schema-回滚" aria-label="Permalink to &quot;8.3 DB schema 回滚&quot;">​</a></h3><p>最难——<strong>DDL 不可逆</strong>:</p><ul><li>加列容易,<strong>删列要谨慎</strong>(先双写,确认没业务依赖,再删)</li><li>改字段类型 = 灾难(用新表 + 双写过渡)</li></ul><blockquote><p><strong>生产 DB 改 schema 要分两阶段</strong>——加(向后兼容)→ 业务迁移 → 删(不可逆,确认后才做)。</p></blockquote><hr><h2 id="九、监控-容灾的-眼睛" tabindex="-1">九、监控:容灾的&quot;眼睛&quot; <a class="header-anchor" href="#九、监控-容灾的-眼睛" aria-label="Permalink to &quot;九、监控:容灾的&quot;眼睛&quot;&quot;">​</a></h2><p>容灾系统必须有<strong>独立的监控</strong>——主系统挂了主监控也挂,看不到真相。</p><h3 id="_9-1-关键指标" tabindex="-1">9.1 关键指标 <a class="header-anchor" href="#_9-1-关键指标" aria-label="Permalink to &quot;9.1 关键指标&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主从复制延迟         秒级</span></span>
<span class="line"><span>备份成功率           每天必须 100%</span></span>
<span class="line"><span>备份完成时间         不能超过 RPO 一半</span></span>
<span class="line"><span>跨机房同步延迟       与 RPO 关联</span></span>
<span class="line"><span>切换演练成功率       100%</span></span></code></pre></div><h3 id="_9-2-报警分级" tabindex="-1">9.2 报警分级 <a class="header-anchor" href="#_9-2-报警分级" aria-label="Permalink to &quot;9.2 报警分级&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P0:可用性掉到 99.9% 以下,立即电话叫醒</span></span>
<span class="line"><span>P1:复制延迟 &gt; 30 秒,15 分钟响应</span></span>
<span class="line"><span>P2:备份失败,工作时间响应</span></span>
<span class="line"><span>P3:配置漂移,周内处理</span></span></code></pre></div><hr><h2 id="十、灾备的成本现实" tabindex="-1">十、灾备的成本现实 <a class="header-anchor" href="#十、灾备的成本现实" aria-label="Permalink to &quot;十、灾备的成本现实&quot;">​</a></h2><p>灾备是<strong>纯成本</strong>——不直接产生收入,但出事时拯救公司。</p><h3 id="_10-1-成本结构" tabindex="-1">10.1 成本结构 <a class="header-anchor" href="#_10-1-成本结构" aria-label="Permalink to &quot;10.1 成本结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>硬件:1.5x ~ 3x(备份系统)</span></span>
<span class="line"><span>人力:专门 SRE 团队</span></span>
<span class="line"><span>带宽:跨地域同步(贵)</span></span>
<span class="line"><span>演练:占用工程时间</span></span>
<span class="line"><span>工具:监控 / 备份软件 license</span></span></code></pre></div><h3 id="_10-2-投入比例" tabindex="-1">10.2 投入比例 <a class="header-anchor" href="#_10-2-投入比例" aria-label="Permalink to &quot;10.2 投入比例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>普通业务:容灾投入 = 总技术成本 × 5-10%</span></span>
<span class="line"><span>核心业务:容灾投入 = 总技术成本 × 20-30%</span></span>
<span class="line"><span>金融业务:容灾投入 = 总技术成本 × 50%+</span></span></code></pre></div><h3 id="_10-3-roi-计算" tabindex="-1">10.3 ROI 计算 <a class="header-anchor" href="#_10-3-roi-计算" aria-label="Permalink to &quot;10.3 ROI 计算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>出事损失 = 业务收入损失 + 客户流失 + 监管罚款 + 公司声誉</span></span>
<span class="line"><span>        = 几百万到几亿(单次)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>灾备成本 = 一年几百万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ 一次灾难就回本</span></span></code></pre></div><blockquote><p><strong>2017 GitLab 事件估计损失千万美元 + 公司差点关门</strong> —— 多投入 100 万搞演练就能避免。</p></blockquote><hr><h2 id="十一、最终架构图" tabindex="-1">十一、最终架构图 <a class="header-anchor" href="#十一、最终架构图" aria-label="Permalink to &quot;十一、最终架构图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                     业务流量</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>                   ┌────┴────┐</span></span>
<span class="line"><span>                   ↓         ↓</span></span>
<span class="line"><span>            主中心(A 城)  灾备中心(A 城)</span></span>
<span class="line"><span>              (Active)      (Active 同城双活)</span></span>
<span class="line"><span>                ↕              ↕</span></span>
<span class="line"><span>                ↕    同城同步    ↕</span></span>
<span class="line"><span>                ↕              ↕</span></span>
<span class="line"><span>                └──────┬───────┘</span></span>
<span class="line"><span>                       ↕</span></span>
<span class="line"><span>                       ↕  异地异步同步</span></span>
<span class="line"><span>                       ↕</span></span>
<span class="line"><span>                  异地容灾(B 城)</span></span>
<span class="line"><span>                  (Standby / 只读)</span></span>
<span class="line"><span>                       ↕</span></span>
<span class="line"><span>                       ↕  备份归档</span></span>
<span class="line"><span>                       ↕</span></span>
<span class="line"><span>                  对象存储(冷备)</span></span>
<span class="line"><span>                  (跨 region)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>监控:独立系统,与业务隔离,看见整体状态</span></span></code></pre></div><hr><h2 id="十二、踩坑提醒" tabindex="-1">十二、踩坑提醒 <a class="header-anchor" href="#十二、踩坑提醒" aria-label="Permalink to &quot;十二、踩坑提醒&quot;">​</a></h2><ol><li><strong>没定 RTO/RPO 就上备份</strong>——目标不清做出来不知道达标没</li><li><strong>备份和源数据共磁盘 / 共机房</strong>——一起死</li><li><strong>不验证备份完整性</strong>——出事时才发现备份是空的</li><li><strong>不演练</strong>——演练时漏洞百出</li><li><strong>没异地副本</strong>——一个城市灾难全完</li><li><strong>备份不加密</strong>——泄漏即数据泄漏</li><li><strong>依赖单一备份方案</strong>——3-2-1 原则</li><li><strong>回滚链路没测</strong>——回滚时发现回不了</li><li><strong>DB schema 不向后兼容</strong>——发布失败回滚不了</li><li><strong>配置中心没备份</strong>——配置丢了恢复不了</li><li><strong>以为云厂商会帮你做</strong>——云厂商的 SLA 是钱,不是你的数据,数据丢了赔不回业务损失</li><li><strong>没有&quot;假设最糟&quot;思维</strong>——所有冗余都失效怎么办?要有 Plan Z</li></ol><hr><p>下一篇:<code>27-数据迁移.md</code>,讲在线数据迁移的几种姿势——<strong>双写 + 数据同步 + 灰度切流</strong>的标准模板,从 MySQL 迁 TiDB / 从 16 库扩到 32 库 / 从单 region 迁多 region 的具体步骤,以及<strong>为什么数据迁移是工程师&quot;最不愿意做但最值得练的工作&quot;</strong>。</p>`,130)])])}const u=s(l,[["render",i]]);export{g as __pageData,u as default};
